MT 0 MB 0
//print traco
for Each Order EmpCod, FilCod, NfeCod Where EmpCod = &EmpCod Where FilCod = &FilCod Where NfeCod = &NfeCod
LeituraXmlDanfe.Call(NfeArqXml,&TNFeProc)
If not &TNFeProc.protNFe.infProt.nProt.IsEmpty() &Protocolo = &TNFeProc.protNFe.infProt.nProt + ' ' + Substr(&TNFeProc.protNFe.infProt.dhRecbto, 9,2) + '/' + Substr(&TNFeProc.protNFe.infProt.dhRecbto, 6,2) + '/' + Substr(&TNFeProc.protNFe.infProt.dhRecbto, 1,4) + ' ' + Substr(&TNFeProc.protNFe.infProt.dhRecbto, 12,8) EndiF
// Do Case // Case NfeSts = Status_NFe.Cancelada // print Cancelada // noSkip // // Case NfeSts <> Status_NFe.Autorizada or &TNFeProc.protNFe.infProt.nProt.IsEmpty() // &Protocolo = 'SEM VALOR FISCAL' // print SemValorFiscal // noSkip // // Case NfeSts = Status_NFe.Autorizada // if &TNFeProc.NFe.infNFe.dest.xNome = 'NF-E EMITIDA EM AMBIENTE DE HOMOLOGACAO - SEM VALOR FISCAL' // print SemValorFiscal // noSkip // EndIf // EndCase Exit EndFor
if not &TNFeProc.protNFe.infProt.chNFe.IsEmpty() &TipoCodigoBarras = TipoCodigoBarras.QrCode RetornaConfiguracoesPastas.Call(&EmpCod, &FilCod, &sdtConfiguracoesPasta) &Arquivo = &sdtConfiguracoesPasta.PastaDiretorioTempFis + trim(&TipoCodigoBarras.ToString()) + &TNFeProc.protNFe.infProt.chNFe.Trim() + '.png'
&valqrCode = &TNFeProc.NFe.infNFeSupl.qrCode.Trim()
//&valqrCode = 'http://www.dfeportal.fazenda.pr.gov.br/dfe-portal/rest/servico/consultaNFCe?chNFe=41160509428476000100650010000000041000000041&nVersao=100&tpAmb=2&cDest=99999999000191&dhEmi=323031362d30352d30345431363a34363a34392d30333a3030&vNF=56.61&vICMS=0.00&digVal=5a68466251564a486b5a4d4d767358554370575070616368346b343d&cIdToken=000001&cHashQRCode=1D3E6BFE469A2CC9DFD4C919863D5376B010BC31' &File.Source = &Arquivo If not &File.Exists() and not &valqrCode.IsEmpty() ExeCodigoBarrasWinWeb_qrCode.Call(&sdtConfiguracoesPasta, &TipoCodigoBarras, &TNFeProc.protNFe.infProt.chNFe.Trim(), &valqrCode) EndIF
&File.Source = &Arquivo If &File.Exists() &QrCode.FromURL(&Arquivo) EndIF EndIF
//&XmlWriter.Open('qrTeste.xml') //&XmlWriter.WriteRawText(&TNFeProc.ToXml()) //&XmlWriter.Close()
//DADOS DA NFE &Varchar = retornaSoNumeros.Udp(&TNFeProc.NFe.infNFe.Id) &ChaveAcesso = substr(&Varchar,1,4) + '.'+ substr(&Varchar,5,4) +'.'+ substr(&Varchar,9,4) +'.'+ substr(&Varchar,13,4) +'.'+ substr(&Varchar,17,4) +'.'+ substr(&Varchar,21,4) +'.'+ substr(&Varchar,25,4) +'.'+ substr(&Varchar,29,4) +'.'+ substr(&Varchar,33,4) +'.'+ substr(&Varchar,37,4) +'.'+ substr(&Varchar,41,4)
&Varchar = padL(trim(&TNFeProc.NFe.infNFe.ide.nNF), 9, '0') &NumeroSerie = 'Número: ' + substr(&Varchar, 1, 3) +'.' + substr(&Varchar, 4, 3) + '.' + substr(&Varchar, 7, 3)
&NumeroSerie += ' Série: ' + padL(trim(&TNFeProc.NFe.infNFe.ide.serie), 3,'0') &NumeroSerie += ' Emissão: ' + substr(&TNFeProc.NFe.infNFe.ide.dhEmi ,9,2) +'/'+ Substr(&TNFeProc.NFe.infNFe.ide.dhEmi,6,2) +'/'+ Substr(&TNFeProc.NFe.infNFe.ide.dhEmi,1,4) + ' ' + Substr(&TNFeProc.NFe.infNFe.ide.dhEmi,12,8)
//&QtdLinhas = GxMlines(&TNFeProc.NFe.infNFe.emit.xNome, 47) //If &QtdLinhas > 1 // &UmFilRaz = GxGetMLi(&TNFeProc.NFe.infNFe.emit.xNome, 1, 47) // &UmFilRaz = UPPER(&UmFilRaz) // print tituloA // // &UmFilRaz = GxGetMLi(&TNFeProc.NFe.infNFe.emit.xNome, 2, 47) // &UmFilRaz = UPPER(&UmFilRaz) // print tituloA //Else &UmFilRaz = &TNFeProc.NFe.infNFe.emit.xNome &UmFilRaz = UPPER(&UmFilRaz) print tituloA //EndIF
&CnpjIeIm = 'CNPJ: ' + trim(&TNFeProc.NFe.infNFe.emit.CNPJ)
If not &TNFeProc.NFe.infNFe.emit.IE.IsEmpty() If not &CnpjIeIm.IsEmpty() &CnpjIeIm += ' - ' EndIf &CnpjIeIm += 'IE: ' + trim(&TNFeProc.NFe.infNFe.emit.IE) EndIF
// If Not FilInsMun.IsEmpty() // If not &CnpjIeIm.IsEmpty() // &CnpjIeIm += ' - ' // EndIf // &CnpjIeIm += 'IM: ' + trim(FilInsMun) // EndIF
&Endereco = &TNFeProc.NFe.infNFe.emit.enderEmit.xLgr.Trim() + ', ' + &TNFeProc.NFe.infNFe.emit.enderEmit.nro.Trim() &Cidade = formataCEP.Udp(&TNFeProc.NFe.infNFe.emit.enderEmit.CEP) + ' ' + &TNFeProc.NFe.infNFe.emit.enderEmit.xMun.Trim() + ' - ' + &TNFeProc.NFe.infNFe.emit.enderEmit.UF.Trim() If not &TNFeProc.NFe.infNFe.emit.enderEmit.xBairro.IsEmpty() &Endereco += ' - ' + &TNFeProc.NFe.infNFe.emit.enderEmit.xBairro.Trim() EndIF
////&Situacao = padL(trim(&Situacao), 3, '0') //If &TNFeProc.NFe.infNFe.emit.CRT = RegimeTributario.RegimeNormal // &TituloCSOSN = 'CST' //Else // &TituloCSOSN = 'CSOSN' //EndIF
//DADOS PRODUTO &PermiteCreditoIcms = 'NFC-e Não permite aproveitamento de crédito de ICMS'
print Cabecalho
//TOTAIS &varPedVlrBrt_VNF = 'R$ ' + trim(&TNFeProc.NFe.infNFe.total.ICMSTot.vNF)
//print TotaisItem
//FORMA PAGAMENTO &Moeda = 0 //print FormaPagamento For &pag in &TNFeProc.NFe.infNFe.pag.detPag If &Pag.tPag = '01' &Tipopagamento = 'Dinheiro' &Moeda += val(&pag.vPag) Endif EndFor if not &Moeda.IsEmpty() &varPedVlrBrt = trim(toformattedString(&Moeda)) do 'addIMpressao' &Moeda = 0 Endif
For &pag in &TNFeProc.NFe.infNFe.pag.detPag If &Pag.tPag = '05' &Tipopagamento = 'Crédito Loja' &Moeda += val(&pag.vPag) Endif EndFor if not &Moeda.IsEmpty() &varPedVlrBrt = trim(toformattedString(&Moeda)) do 'addIMpressao' &Moeda = 0 Endif
&QtdVezes = 0 For &pag in &TNFeProc.NFe.infNFe.pag.detPag If &Pag.tPag = '03' &Tipopagamento = 'Cartão Crédito' &Moeda += val(&pag.vPag) &QtdVezes += 1 Endif EndFor if not &Moeda.IsEmpty() if &QtdVezes > 1 &Tipopagamento += ' ('+trim(str(&QtdVezes))+' Vezes)' Else &Tipopagamento += ' (1 Vez)' Endif
&varPedVlrBrt = trim(toformattedString(&Moeda)) do 'addIMpressao' &Moeda = 0 Endif
For &pag in &TNFeProc.NFe.infNFe.pag.detPag &Tipopagamento = '' do case Case &Pag.tPag = '02' &Tipopagamento = 'Cheque' Case &Pag.tPag = '04' &Tipopagamento = 'Cartão Débito' Case &Pag.tPag = '10' &Tipopagamento = 'Vale Alimentação' Case &Pag.tPag = '11' &Tipopagamento = 'Vale Refeição' Case &Pag.tPag = '12' &Tipopagamento = 'Vale Presente' Case &Pag.tPag = '13' &Tipopagamento = 'Vale Combustível' Case &Pag.tPag = '99' &Tipopagamento = 'Outros' Endcase
&varPedVlrBrt = &pag.vPag
if not &Tipopagamento.IsEmpty() do 'addIMpressao' &Tipopagamento = '' Endif EndFor
&NfeVlrTotApxTrib = val(&TNFeProc.NFe.infNFe.total.ICMSTot.vTotTrib) &NfeVlrTotPro = val(&TNFeProc.NFe.infNFe.total.ICMSTot.vProd) If &NfeVlrTotApxTrib <> 0 //&Percentual = round((&NfeVlrTotApxTrib / &NfeVlrTotPro) * 100,2) &TotalPagoTributos = 'R$ ' + trim(&NfeVlrTotApxTrib.ToFormattedString())//'(' + trim(ToformattedString(&Percentual)) + '%)' // print Tributos EndIF
//DADOS ADICIONAIS &Mensagem = &TNFeProc.NFe.infNFe.infAdic.infCpl + &TNFeProc.NFe.infNFe.infAdic.infAdFisco &QtdLinhaObs = gxMLines(&Mensagem, 47) if &QtdLinhaObs > 0 // print tituloObs EndIF
For &Count = 1 to &QtdLinhaObs &Observacao = GxGetMLi(&Mensagem, &Count, 47)
do case case &Observacao1.IsEmpty() &Observacao1 = &Observacao case &Observacao2.IsEmpty() &Observacao2 = &Observacao case &Observacao3.IsEmpty() &Observacao3 = &Observacao case &Observacao4.IsEmpty() &Observacao4 = &Observacao case &Observacao5.IsEmpty() &Observacao5 = &Observacao case &Observacao6.IsEmpty() &Observacao6 = &Observacao endcase
// print ObservacaoNFce EndFor
//print Subtitulo
//print Consumidor //DADOS DESTINATARIO &NfeCliRaz = &TNFeProc.NFe.infNFe.dest.xNome do case case not &TNFeProc.NFe.infNFe.dest.CNPJ.IsEmpty() &NfecpfCnpj = &TNFeProc.NFe.infNFe.dest.CNPJ + ' - ' + &NfeCliRaz.Trim() ValidaCpfCnpj.call(&NfecpfCnpj, &Valida, 'N') &Varchar1 = 'PJ: ' + trim(&NfecpfCnpj) &Varchar = &NfeCliRaz.Trim() Case Not &TNFeProc.NFe.infNFe.dest.CPF.IsEmpty() &NfecpfCnpj = &TNFeProc.NFe.infNFe.dest.CPF ValidaCpfCnpj.call(&NfecpfCnpj, &Valida, 'N') &Varchar1 = 'PF: ' + trim(&NfecpfCnpj) &Varchar = &NfeCliRaz.Trim() Otherwise &Varchar = 'CONSUMIDOR NÃO IDENTIFICADO' EndCase
//&QtdLinhaObs = gxmLines(&Varchar, 47) //For &Count = 1 to &QtdLinhaObs &NomeConsumidor = &Varchar &NomeConsumidor1 = &Varchar1 // print NomeConsumidor //EndFor
//print QrCod
&Data = serverdate() &DadosGeracao = 'Gerado em ' + trim(toformattedString(&Data)) + ' às ' + sysTime() + ' pelo sistema JASPI - www.jaspi.com.br' //print rodape
For &det in &TNFeProc.NFe.infNFe.dets &QtdItens += 1 EndFor
print printtudo
print TituloProduto print traco noSkip
For &det in &TNFeProc.NFe.infNFe.dets &ProNom1.SetEmpty() if &IsPrimeiro = true Print dosh noSkip endif
if &det.prod.cEAN.IsEmpty() or &det.prod.cEAN = 'SEM GTIN' &ProBar = &det.prod.cProd Else &ProBar = &det.prod.cEAN EndIF
&ProEmbUnd = &det.prod.uCom &ProNom = &det.prod.xProd
&PedQtd = val(&det.prod.qCom) &Quantidade = trim(toformattedString(&PedQtd))
&PedVlrUnt = val(&det.prod.vUnCom) &PedVlrItm = val(&det.prod.vProd)
&TributosUnitario = val(&det.imposto.vTotTrib) print Produto
&IsPrimeiro = true
&ProNom1 = &det.infAdProd if not &det.prod.comb.cProdANP.IsEmpty() &ProNom1 += ' CÓD. PRODUTO ANP: ' + trim(&det.prod.comb.cProdANP) &ProNom1 += ' UF DE CONSUMO: ' + &det.prod.comb.UFCons.Trim() Endif
if not &ProNom1.IsEmpty() print DadosAdicionais Endif
// print ProdutoQuantidades EndFor
print traco
sub 'addIMpressao' do Case Case &Tipopagamento1.IsEmpty() &Tipopagamento1 = &Tipopagamento &varPedVlrBrt1 = &varPedVlrBrt Case &Tipopagamento2.IsEmpty() &Tipopagamento2 = &Tipopagamento &varPedVlrBrt2 = &varPedVlrBrt Case &Tipopagamento3.IsEmpty() &Tipopagamento3 = &Tipopagamento &varPedVlrBrt3 = &varPedVlrBrt Case &Tipopagamento4.IsEmpty() &Tipopagamento4 = &Tipopagamento &varPedVlrBrt4 = &varPedVlrBrt EndCase EndSub
